    <rect x="260" y="166" width="200" height="70" rx="10" fill="#1c1c1f" stroke="#38bdf8" stroke-width="1.5"/>
    <text x="360" y="192" fill="#fafafa" font-size="13" font-weight="700" text-anchor="middle">Libra digital (CBDC)</text>
    <text x="360" y="210" fill="#a1a1aa" font-size="12" text-anchor="middle">Propuesta del Banco de Inglaterra</text>
    <text x="360" y="226" fill="#a1a1aa" font-size="12" text-anchor="middle">Reunión privada con Bailey (sep. 2025)</text>

